import * as path from "path";

import * as AasTypes from "../src/types";
import * as AasJsonization from "../src/jsonization";

import * as TestCommon from "./common";

/**
 * Load a maximal example of {@link types.SomeItem} from
 * the test data directory.
 */
export function loadMaximalSomeItem(
): AasTypes.SomeItem {
  const aPath = path.join(
    TestCommon.TEST_DATA_DIR,
    "Json",
    "Expected",
    "SomeItem",
    "maximal.json"
  );

  const jsonable = TestCommon.readJsonFromFileSync(aPath);

  const instanceOrError = AasJsonization.someItemFromJsonable(
    jsonable
  );
  expect(instanceOrError.error).toBeNull();
  const instance = instanceOrError.mustValue();

  const casted = AasTypes.asSomeItem(instance);
  if (casted === null) {
    throw new Error(
      `Expected instance of SomeItem in ${aPath}, ` +
      `but got: ${typeof instance}`
    );
  }
  return casted;
}

